insert into content_tips (id, course_id, unit_order, cefr_level, skill, type, topic, title, body, example) values
('0fdc35b3-35a2-5ed8-a4ea-3fda4629ec96'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,1,'A1',$p$speaking$p$,$p$error_comun$p$,$p$ser_apresentacao$p$,$p$«Você» habla en tercera persona$p$,$p$Aunque «você» significa 'tú', el verbo va como con él/ella: «você é», nunca «você és». Así queda SER: eu sou, você é, nós somos — y al presentarte, un «Muito prazer!» abre todas las puertas.$p$,$p$Eu sou o Pedro · Você é a Maria? · Nós somos amigos · Muito prazer!$p$),
('dbf63ab6-15f6-50f3-a9bb-1169f2968893'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,2,'A1',$p$writing$p$,$p$gramatica$p$,$p$posesivos_genero$p$,$p$¿Meu o minha? Manda la cosa, no el dueño$p$,$p$El posesivo concuerda con el género de lo que posees: «pai» es masculino → «meu pai»; «mãe» es femenina → «minha mãe», lo diga un hombre o una mujer. Y para decir qué tienes, el verbo TER: eu tenho, você tem.$p$,$p$meu pai · minha mãe · seu carro · sua casa · Eu tenho dois irmãos$p$),
('a9ecb07a-3ca8-53e6-b45c-1a3134e90bff'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,3,'A1',$p$writing$p$,$p$gramatica$p$,$p$rutina_presente$p$,$p$«Gostar» nunca camina solo: siempre con «de»$p$,$p$El presente de los verbos en -AR te sonará familiar: eu moro, eu trabalho, você mora. Pero «gostar» siempre pide «de», incluso antes de otro verbo: «gosto de estudar», jamás «gosto estudar».$p$,$p$Eu moro em São Paulo · Trabalho todos os dias · Gosto de café · Gosto de estudar português$p$),
('73ae4d22-6dea-598f-b2f2-cb9e009f1800'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,4,'A1',$p$speaking$p$,$p$cultura$p$,$p$pedir_precos$p$,$p$«Queria» te hace más amable$p$,$p$Para pedir, «eu quero» funciona, pero «eu queria» suena más suave y cortés: es el favorito de los brasileños en cafés y tiendas. Para el precio, pregunta «Quanto custa?» y la respuesta llega en reales: «São cinco reais».$p$,$p$Eu queria um café, por favor · Quanto custa? · São cinco reais$p$),
('17ee9c3a-2eae-51f5-bdd2-9bf13bd9cf98'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,5,'A1',$p$listening$p$,$p$error_comun$p$,$p$ficar_localizacao$p$,$p$En Brasil los lugares no están: «ficam»$p$,$p$Para ubicar, el pt-BR prefiere FICAR: «Onde fica o banco?» suena mucho más natural que «onde está». Y para entender la respuesta, tus tres brújulas: perto de (cerca de), longe de (lejos de), ao lado de (al lado de).$p$,$p$Onde fica o banco? · Fica perto da praça · Longe do hotel · Ao lado do mercado$p$),
('5a2fd8d1-2ec4-5d30-b3be-5bb27bb83a8a'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,6,'A1',$p$reading$p$,$p$mnemotecnia$p$,$p$gostar_frequencia$p$,$p$Segunda-feira es lunes: ¡domingo cuenta primero!$p$,$p$Los días laborales se numeran contando desde el domingo: segunda-feira (lunes), terça, quarta… y van siempre en minúscula. Para tus pasatiempos, «gostar de + infinitivo» con su dosis de frecuencia: sempre, às vezes, nunca.$p$,$p$Gosto de jogar futebol aos sábados · Sempre estudo de manhã · Às vezes danço · segunda-feira · terça-feira$p$),
('962ca4fb-0a65-5615-a87a-292025283980'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,7,'A2',$p$writing$p$,$p$gramatica$p$,$p$passe_compose_reguliers$p$,$p$El pasado en dos piezas$p$,$p$El passé composé se arma con avoir en presente + participio: los verbos en -er hacen -é (manger → mangé). Memoriza los irregulares estrella: fait, pris, vu, eu, bu.$p$,$p$Hier, j'ai mangé une pomme. · Tu as fait le ménage ? · Nous avons vu un film.$p$),
('ef992894-8fc7-583e-bd97-985af1b54b5b'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,8,'A2',$p$listening$p$,$p$gramatica$p$,$p$futur_proche$p$,$p$Dos futuros, dos sabores$p$,$p$Para un plan cercano usa el futur proche: «je vais + infinitivo», igual que el español «voy a…» — es el que más oirás en la calle. El futur simple (je parlerai) sirve para promesas y predicciones; sus irregulares clave son serai, aurai, irai, ferai.$p$,$p$Demain, je vais visiter le Louvre. · Un jour, je parlerai couramment français.$p$),
('5cf45928-71ac-59d1-9d72-a88bbcaffc3e'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,9,'A2',$p$writing$p$,$p$error_comun$p$,$p$accord_participe$p$,$p$Con être, el participio se viste$p$,$p$Los verbos de movimiento van con être y el participio concuerda con el sujeto: elle → allée, ils → partis. Con avoir el participio nunca cambia: «elle a mangé», sin -e extra.$p$,$p$Elle est allée au marché. · Ils sont partis en train. · Elles sont arrivées hier.$p$),
('d9a4bf95-6f8d-58dd-8472-81f58330cab4'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,10,'A2',$p$reading$p$,$p$error_comun$p$,$p$comparatif$p$,$p$«Plus bon» no existe$p$,$p$Para comparar: plus/moins/aussi + adjetivo + que. El comparativo de bon es meilleur — nunca digas «plus bon». Con cantidades, «de» va sin artículo: beaucoup de pain, un peu de lait.$p$,$p$Ce café est meilleur que l'autre. · Elle est aussi grande que moi. · J'achète beaucoup de pain.$p$),
('933cc70c-0815-5553-a61a-657f3ef7f234'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,11,'A2',$p$reading$p$,$p$mnemotecnia$p$,$p$imparfait_intro$p$,$p$El imparfait pinta el decorado$p$,$p$Piensa en una escena de película: el imparfait es el decorado (cómo era, qué había, lo que hacías de costumbre) y el passé composé es la acción que irrumpe. Frases ancla: c'était, il y avait, quand j'étais petit.$p$,$p$Quand j'étais petit, il y avait un jardin. C'était magnifique… et un jour, tout a changé.$p$),
('f9d0e221-257f-523d-b7e9-14b9008ec3bb'::uuid,'20000000-0000-0000-0000-000000000003'::uuid,12,'A2',$p$speaking$p$,$p$gramatica$p$,$p$avoir_mal_a$p$,$p$¿Dónde te duele? Dilo con à$p$,$p$«Avoir mal à» se contrae con el artículo: à + le = au (au dos), à + les = aux (aux dents); con la no cambia (à la tête). Para dar consejos usa «il faut + infinitivo» o «tu devrais…».$p$,$p$J'ai mal à la tête et au dos. · Tu devrais te reposer. · Il faut boire de l'eau.$p$),
('28afbe4e-a910-5bca-aa70-e902712cbe07'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,7,'A2',$p$writing$p$,$p$gramatica$p$,$p$passato_avere$p$,$p$Ho fatto, ho visto: el pasado con avere$p$,$p$El passato prossimo con AVERE se forma con avere en presente + participio: los verbos en -are hacen -ato (mangiare → mangiato). Memoriza los irregulares clave: fatto, preso, visto, letto, bevuto. Con avere el participio NO concuerda con el sujeto: «Maria ha mangiato», nunca «ha mangiata».$p$,$p$ho mangiato · hai fatto · abbiamo visto · hanno letto un libro$p$),
('2b3f63eb-876c-577d-99f0-591d38d2071b'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,8,'A2',$p$writing$p$,$p$error_comun$p$,$p$futuro_regolare$p$,$p$Mangerò, no mangiarò: la e del futuro$p$,$p$El futuro semplice termina en -ò, -ai, -à: parlerò, finirò. Ojo con la ortografía: los verbos en -are cambian la a por e (mangiare → mangerò, comprare → comprerò), el error típico es escribir «mangiarò». Los irregulares más frecuentes acortan la raíz: sarò, avrò, andrò, farò, verrò.$p$,$p$domani parlerò · mangerò una pizza · comprerò il biglietto · sarò a Roma$p$),
('e603ce4e-4df1-59b8-b1ef-9b67bc46248f'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,9,'A2',$p$speaking$p$,$p$mnemotecnia$p$,$p$concordanza$p$,$p$Con essere, el participio se viste del sujeto$p$,$p$Los verbos de movimiento y estado (andare, venire, partire, arrivare…) forman el passato prossimo con ESSERE, y el participio concuerda con el sujeto como si fuera un adjetivo: «lei è andata», «loro sono partiti». Truco: pregúntate quién lo hizo y viste el participio con su ropa (-o, -a, -i, -e). Por eso «sono andato» lo dice él y «sono andata» lo dice ella.$p$,$p$lui è andato · lei è andata · loro sono partiti · le ragazze sono arrivate$p$),
('4689a461-2c5b-5467-8e24-b5e53a604edd'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,10,'A2',$p$speaking$p$,$p$gramatica$p$,$p$comparativo$p$,$p$¿Più grande DI o CHE? Depende de qué compares$p$,$p$Para comparar dos nombres usa «più/meno + adjetivo + DI»: «Milano è più grande di Verona». Entre dos adjetivos (o dos verbos) usa CHE: «è più bello che comodo». Ojo: se dice «migliore», no «più buono»; y para las cantidades está el pronombre «ne»: «ne voglio due».$p$,$p$più grande di Roma · più bello che comodo · questo caffè è migliore · ne voglio due$p$),
('74a2d57d-6836-5f0a-896d-1d0b31d5a0d6'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,11,'A2',$p$reading$p$,$p$gramatica$p$,$p$imperfetto$p$,$p$El imperfetto pinta, el passato prossimo dispara$p$,$p$El imperfetto describe el escenario del pasado: cómo eras, qué había, qué tiempo hacía («ero stanco», «c'era il sole», «faceva freddo»). El passato prossimo cuenta la acción puntual que pasó: «mentre dormivo, ha squillato il telefono». Essere es irregular: ero, eri, era.$p$,$p$ero stanco · avevo fame · c'era il sole · faceva freddo · ha squillato il telefono$p$),
('360793ea-171c-5459-879f-c0ea62e62a15'::uuid,'20000000-0000-0000-0000-000000000004'::uuid,12,'A2',$p$speaking$p$,$p$error_comun$p$,$p$mal_di$p$,$p$Mal di testa: sin artículo, sin excepciones$p$,$p$«Avere mal di» va SIN artículo: «ho mal di testa», «ho mal di gola» — nunca «mal della testa». La alternativa con artículo es otra estructura: «mi fa male la testa» (me duele la cabeza). Para dar consejos usa «bisogna + infinitivo» o el suave «dovresti…».$p$,$p$ho mal di testa · mi fa male la gola · bisogna riposare · dovresti bere più acqua$p$)
